const ListOIDCClients = `-- name: ListOIDCClients :many
SELECT id, name, description, client_secret, redirect_uris, grants, response_types, scopes, token_endpoint_auth_method, application_type, client_uri, logo_uri, policy_uri, tos_uri, is_first_party, created_at, updated_at FROM oidc_clients
ORDER BY created_at DESC
`

func (q *Queries) ListOIDCClients(ctx context.Context) ([]OidcClient, error) {
	rows, err := q.db.QueryContext(ctx, ListOIDCClients)
	if err != nil {
		return nil, err
	}
	defer rows.Close()
	items := []OidcClient{}
	for rows.Next() {
		var i OidcClient
		if err := rows.Scan(
			&i.ID,
			&i.Name,
			&i.Description,
			&i.ClientSecret,
			&i.RedirectUris,
			&i.Grants,
			&i.ResponseTypes,
			&i.Scopes,
			&i.TokenEndpointAuthMethod,
			&i.ApplicationType,
			&i.ClientUri,
			&i.LogoUri,
			&i.PolicyUri,
			&i.TosUri,
			&i.IsFirstParty,
			&i.CreatedAt,
			&i.UpdatedAt,
		); err != nil {
			return nil, err
		}
		items = append(items, i)
	}
	if err := rows.Close(); err != nil {
		return nil, err
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return items, nil
}

